/**
 * method
 * @name f_cntrSeqSearch
 * @description 미지정(컨테이너, 차량)의 컨테이너 SEQ 세팅
 */
scwin.f_cntrSeqSearch = async function (row, cntrNo) {
  let rowObj = ds_info2.getRowJSON(row);
  if (cntrNo == undefined) {
    cntrNo = rowObj.cntrNo;
  }
  if (rowObj.cntrSeq == 0 && !$c.gus.cfIsNull($p, cntrNo)) {
    dma_retriveCntrNoSeqInfo.setJSON({
      "cntrNo": cntrNo,
      "odrNo": rowObj.odrNo,
      "alloccarNo": rowObj.alloccarNo,
      "alloccarSeq": rowObj.alloccarSeq,
      "reqClsCd": rowObj.reqClsCd
    });
    let e = await $c.sbm.execute($p, sbm_cntrNoSeqInfo);
    //submit-done 이벤트가 등록되어 있으면 await $c.sbm.execute로 호출시 이후 코드가 실행되지 않아서 이벤트에서 제거하고 직접실행함
    scwin.sbm_cntrNoSeqInfo_submitdone(e);
  }
};

