/**
 * method
 * @name chkDateValue
 * @description
 */
scwin.chkDateValue = function (row, rowObj, chkDate, chkDateName) {
  let ret = {
    success: false,
    msg: null
  };
  if (rowObj.dptDt != "" && rowObj.dptHh != "" && rowObj.arvDt != "" && rowObj.arvHh != "" && rowObj.dptDt + rowObj.dptHh >= rowObj.arvDt + rowObj.arvHh) {
    ret.msg = "출발일자가 도착일자보다 큽니다";
    return ret;
  }
  let chkRowObj = null;
  for (let idx = 0; idx < row; ++idx) {
    chkRowObj = ds_info2.getRowJSON(idx);
    if (chkRowObj.odrNo != rowObj.odrNo || chkRowObj.cntrSeq != rowObj.cntrSeq) {
      continue;
    }
    if (chkRowObj.dptDt != "" && chkRowObj.dptHh != "" && chkDate <= chkRowObj.dptDt + chkRowObj.dptHh) {
      ret.msg = chkDateName + "가 이전단계 출발일자보다 작습니다";
      return ret;
    }
    if (chkRowObj.arvDt != "" && chkRowObj.arvHh != "" && chkDate <= chkRowObj.arvDt + chkRowObj.arvHh) {
      ret.msg = chkDateName + "가 이전단계 도착일자보다 작습니다";
      return ret;
    }
  }
  ret.success = true;
  return ret;
};

